function initChecklist(d){if(document.all&&document.getElementById){var a=document.getElementById(d);if(a!=null){var e=a.getElementsByTagName("label");for(var b=0;b<e.length;b++){var c=e[b];c.onmouseover=function(){this.className+=" hover"};c.onmouseout=function(){this.className=this.className.replace(" hover","")}}}}}function validateCheckList(a,f,e,c){if(e){var b=document.getElementById(f);if(b){var d=b[a];for(i=0;i<d.length;i++){if(d[i].checked){return null}}return c[0]}}};